#include <windows.h>

BOOL CISPDockingDlg::ReadFirmware(DWORD dwSize)
{
    uint8_t* pBuffer = new uint8_t[dwSize];
    DWORD dwRead = 0;
    BOOL bResult = ReadFile(m_hDevice, pBuffer, dwSize, &dwRead, NULL);
    if (!bResult) {
        // Memory leak: pBuffer is never freed on this path
        return FALSE;
    }
    ProcessFirmware(pBuffer, dwRead);
    delete[] pBuffer;
    return TRUE;
}
